{
    "level": "A1–B1",
    "intro": "У цьому підрозділі зібрано головні типи питань в англійській: від базових yes / no questions до negative questions і question tags.",
    "rules": [
        {
            "label": "Yes / No",
            "color": "emerald",
            "text": "<strong>Загальні питання</strong> — відповідь yes або no:",
            "example": "Do you like coffee?"
        },
        {
            "label": "Wh",
            "color": "blue",
            "text": "<strong>Wh-questions</strong> — питання з question words:",
            "example": "What do you want?"
        },
        {
            "label": "Tags & Negatives",
            "color": "rose",
            "text": "<strong>Question tags</strong> і <strong>negative questions</strong> додають підтвердження, здивування або очікування:",
            "example": "You know him, don't you? / Don't you know him?"
        }
    ]
}
